CREATE TABLE Agents (\n    agent_id INT PRIMARY KEY AUTO_INCREMENT,\n    agent_name VARCHAR(255) NOT NULL,\n    skill_id INT,\n    status ENUM('Active', 'Inactive') NOT NULL,\n    FOREIGN KEY (skill_id) REFERENCES Skills(skill_id)\n);\n\nCREATE TABLE Shifts (\n    shift_id INT PRIMARY KEY AUTO_INCREMENT,\n    shift_start DATETIME NOT NULL,\n    shift_end DATETIME NOT NULL,\n    agent_id INT,\n    FOREIGN KEY (agent_id) REFERENCES Agents(agent_id)\n);\n\nCREATE TABLE Skills (\n    skill_id INT PRIMARY KEY AUTO_INCREMENT,\n    skill_name VARCHAR(255) NOT NULL\n);\n\nCREATE TABLE Calls (\n    call_id INT PRIMARY KEY AUTO_INCREMENT,\n    agent_id INT,\n    call_start DATETIME NOT NULL,\n    call_end DATETIME NOT NULL,\n    call_duration INT GENERATED ALWAYS AS (TIMESTAMPDIFF(SECOND, call_start, call_end)) STORED,\n    FOREIGN KEY (agent_id) REFERENCES Agents(agent_id)\n);\n\nCREATE TABLE Breaks (\n    break_id INT PRIMARY KEY AUTO_INCREMENT,\n    agent_id INT,\n    break_start DATETIME NOT NULL,\n    break_end DATETIME NOT NULL,\n    FOREIGN KEY (agent_id) REFERENCES Agents(agent_id)\n);\n\nCREATE TABLE Analytics (\n    analytics_id INT PRIMARY KEY AUTO_INCREMENT,\n    date DATE NOT NULL,\n    total_calls INT,\n    average_call_duration FLOAT,\n    total_breaks INT\n);